import{_ as r,C as o,o as l,c as s,E as a,w as i,a as t,a0 as g}from"./chunks/framework.CkNTPv-z.js";const b=JSON.parse('{"title":"Hungary Legal Rights","description":"Legal rights for transgender people in Hungary","frontmatter":{"layout":"doc","title":"Hungary Legal Rights","description":"Legal rights for transgender people in Hungary"},"headers":[],"relativePath":"europe/hungary/legal-rights.md","filePath":"europe/hungary/legal-rights.md","lastUpdated":null}'),d={name:"europe/hungary/legal-rights.md"};function c(u,e,h,m,p,f){const n=o("Badge");return l(),s("div",null,[a(n,{variant:"red"},{default:i(()=>[...e[0]||(e[0]=[t("Legal Gender Recognition Banned",-1)])]),_:1}),a(n,{variant:"red"},{default:i(()=>[...e[1]||(e[1]=[t("2021 Child Protection Law",-1)])]),_:1}),a(n,{variant:"red"},{default:i(()=>[...e[2]||(e[2]=[t("Government Hostility",-1)])]),_:1}),e[3]||(e[3]=g('<h1 id="legal-rights-in-hungary" tabindex="-1">Legal Rights in Hungary <a class="header-anchor" href="#legal-rights-in-hungary" aria-label="Permalink to &quot;Legal Rights in Hungary&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Hungary <strong>completely banned legal gender recognition</strong> in 2023 after previously banning it for minors in 2020:</p><ul><li><strong>Current status</strong>: No legal gender change is possible under any circumstances</li><li><strong>2020 ban</strong>: Government decree prohibited gender marker changes on official documents for anyone born with &quot;constitutional gender identity&quot;</li><li><strong>2023 complete ban</strong>: Any remaining pathways were closed — no court or administrative route exists</li><li><strong>Impact</strong>: Trans people are forced to carry documents showing a gender that does not match their identity</li><li><strong>ECHR rulings</strong>: Multiple cases pending at the European Court of Human Rights</li></ul><h3 id="background" tabindex="-1">Background <a class="header-anchor" href="#background" aria-label="Permalink to &quot;Background&quot;">​</a></h3><ul><li>Before 2020: Hungary had a medicalized but functioning system requiring diagnosis and court approval</li><li>2020: Government banned gender recognition for minors via decree</li><li>2023: Complete ban enacted, eliminating all pathways for adults as well</li><li>The ban is part of broader government anti-LGBTQ+ policies</li></ul><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><ul><li>Name changes are <strong>still legally possible</strong> in some circumstances</li><li>Processed through the <strong>Civil Registry Office</strong> (Anyakönyvi Hivatal)</li><li>Must demonstrate a &quot;legitimate interest&quot; for the change</li><li>Gender transition is not currently accepted as a valid reason by many registrars</li><li>Outcomes are inconsistent and may require legal appeals</li></ul><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><ul><li><strong>Employment</strong>: The Equal Treatment Authority (Egyenlő Bánásmód Hatóság) theoretically covers discrimination</li><li><strong>Gender identity</strong> was previously protected under broad interpretations of the Equal Treatment Act</li><li><strong>2021 &quot;Child Protection&quot; Law</strong>: Banned &quot;portrayal or promotion of homosexuality or gender reassignment&quot; to minors <ul><li>Affects education, media, and public discourse</li><li>Created a hostile environment for LGBTQ+ people</li><li>EU has initiated infringement proceedings against Hungary</li></ul></li><li>Enforcement of anti-discrimination protections has weakened significantly</li></ul><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><ul><li>The <strong>Criminal Code</strong> includes hate crime provisions for sexual orientation</li><li>Gender identity is <strong>not explicitly included</strong></li><li>No enhanced penalties for anti-trans hate crimes</li><li>Police and prosecutors rarely apply existing protections for LGBTQ+ victims</li><li>Government rhetoric has been linked to increased hate incidents</li></ul><h2 id="document-recognition" tabindex="-1">Document Recognition <a class="header-anchor" href="#document-recognition" aria-label="Permalink to &quot;Document Recognition&quot;">​</a></h2><ul><li>Hungarian ID cards, passports, and birth certificates <strong>cannot</strong> be updated to reflect correct gender</li><li>Documents show sex assigned at birth</li><li>Trans people face frequent harassment and discrimination when presenting documents</li><li>International travel can be stressful due to document mismatch</li><li>Some trans people seek gender recognition in other EU countries through legal migration</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://en.hatter.hu/" target="_blank" rel="noreferrer">Háttér Society</a></li><li><a href="https://transvanilla.hu/" target="_blank" rel="noreferrer">Transvanilla Transgender Association</a></li><li><a href="https://www.ilga-europe.org/country/hungary/" target="_blank" rel="noreferrer">ILGA-Europe - Hungary</a></li><li><a href="https://tasz.hu/" target="_blank" rel="noreferrer">Hungarian Civil Liberties Union (TASZ)</a></li></ul>',16))])}const q=r(d,[["render",c]]);export{b as __pageData,q as default};
